import{_ as s,o as t,c as n,O as l}from"./chunks/framework.92cbe775.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"product/hot-update.md","filePath":"product/hot-update.md","lastUpdated":1776007434000}'),r={name:"product/hot-update.md"};function d(c,a,e,i,p,o){return t(),n("div",null,a[0]||(a[0]=[l('<div class="brand-page-shell brand-page-shell--hot-update"><section class="brand-hero"><div><p class="brand-kicker">Hot Update</p><h1>热更新说明</h1><div class="brand-hero__panel"><span class="brand-pill">Controlled Update</span><strong>热更新不是客户绕过平台自己上线，而是在当前租户范围内完成审核、注册、授权后正式生效。</strong><p>把这条链路单独拆页，是为了让售前、实施、培训和客户沟通都能直接引用同一份说明。</p></div><p class="brand-lead"> ExecGov 当前支持客户在不重部署整个平台的前提下，持续新增或更新脚本型能力。 但这条链路仍然是<strong>受控更新</strong>，不是开放式自助发版。 </p><div class="brand-chip-list"><span class="brand-chip">审核同步</span><span class="brand-chip">注册授权</span><span class="brand-chip">租户隔离</span><span class="brand-chip">持续交付</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="./customer-flow.html">回到客户流程 / 交付</a><a class="cta-button" href="./onboarding-checklist.html">查看接入准备清单</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECGOV // HOT UPDATE</span><span>DOC 09</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">updateFlow</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__punct">[</span><span class="matrix-panel__string">&#39;review&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;sync&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;register&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;authorize&#39;</span><span class="matrix-panel__punct">]</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">scope</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__string">&#39;current_tenant_only&#39;</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">publishMode</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__string">&#39;controlled&#39;</span></span></div><div class="matrix-panel__callout">UPDATE WITHOUT BREAKING TENANT BOUNDARY</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">review</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">required</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">scope</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">tenant</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">effect</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">no_full_redeploy</span></span></div></div></div></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">What It Means</p><h2>热更新当前到底指什么</h2><ul class="brand-list"><li>新增脚本或新版本脚本接入时，不需要重部署整个平台</li><li>平台继续保留审核、同步、注册和授权控制权</li><li>更新后的能力只在所属租户范围内生效</li><li>AI 推荐范围仍然受租户与权限共同约束</li></ul></article><article class="brand-card"><p class="brand-kicker">What It Is Not</p><h2>热更新当前不代表什么</h2><ul class="brand-list"><li>不代表客户可以绕过平台直接正式上线</li><li>不代表一更新就自动对所有租户开放</li><li>不代表浏览器直接访问本地目录或内网路径</li><li>不代表平台已经开放成完全自助的能力市场</li></ul></article></section><section class="brand-card"><p class="brand-kicker">Hot Update Flow</p><h2>客户脚本热更新怎么走</h2><div class="brand-grid brand-grid--three"><article class="brand-card brand-card--nested"><h3>1. 准备脚本目录</h3><p>按约定准备脚本目录，至少包含入口脚本和 <code>README.md</code>。当前 Python / Shell 文本脚本默认入口分别是 <code>main.py</code> / <code>main.sh</code>。</p></article><article class="brand-card brand-card--nested"><h3>2. 提交到所属租户范围</h3><p>客户把脚本放到自己的租户目录，不同客户不能混用目录，<code>public/</code> 仅由平台维护。</p></article><article class="brand-card brand-card--nested"><h3>3. 平台审核</h3><p>平台确认该脚本属于哪个租户、是否允许 AI 调用、是否允许手动执行、是否需要人工确认。</p></article><article class="brand-card brand-card--nested"><h3>4. 平台同步到执行目录</h3><p>平台运行时使用的是受控相对路径，而不是执行脚本仓库外的任意绝对路径。</p></article><article class="brand-card brand-card--nested"><h3>5. 完成注册与授权</h3><p>平台会完成 Script 注册、Script 版本登记、Skill 关联、Skill 版本登记和租户授权绑定。</p></article><article class="brand-card brand-card--nested"><h3>6. 权限验证后正式可用</h3><p>平台会验证当前租户可见可执行、其他租户不可见不可执行，确认 AI 推荐范围没有串租户。</p></article></div></section><section class="brand-card"><p class="brand-kicker">Hot Update Submit</p><h2>客户发起热更新时，通常一次提供这些信息</h2><table class="hot-update-submit-table"><thead><tr><th>提交项</th><th>是否必须</th><th>用途</th><th>说明</th></tr></thead><tbody><tr><td>脚本文件</td><td>必须</td><td>作为实际执行内容</td><td>至少包含约定入口文件；当前 Python / Shell 默认是 <code>main.py</code> / <code>main.sh</code></td></tr><tr><td>README.md</td><td>必须</td><td>给平台审核和后续维护使用</td><td>建议写明作用、输入、输出、前置条件、是否生成文件</td></tr><tr><td>所属租户</td><td>必须</td><td>决定脚本最终授权范围</td><td>不同客户不能混用目录和授权</td></tr><tr><td>业务场景说明</td><td>必须</td><td>帮助平台判断接入方式和命名</td><td>建议说明脚本解决什么问题、面向谁使用</td></tr><tr><td>是否允许 AI 调用</td><td>建议提供</td><td>决定智能大脑是否可推荐该能力</td><td>不是所有脚本都默认进入 AI 推荐范围</td></tr><tr><td>是否允许手动执行</td><td>建议提供</td><td>决定页面是否开放手动入口</td><td>可与 AI 调用分开控制</td></tr><tr><td>是否需要人工确认</td><td>建议提供</td><td>控制高风险动作的确认环节</td><td>适用于会改写数据或触发外部动作的能力</td></tr></tbody></table></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Why It Matters</p><h2>热更新真正带来的效果</h2><ul class="brand-list"><li>平台本身不需要重新部署</li><li>当前租户可以直接看到新能力或新版本</li><li>其他租户不会受到影响</li><li>平台方仍保留审核、注册和授权控制权</li></ul></article><article class="brand-card"><p class="brand-kicker">Misunderstanding</p><h2>几个常见误解，最好提前说清楚</h2><ul class="brand-list"><li>热更新不等于客户可以绕过平台直接上线</li><li>热更新不等于一更新就对所有租户开放</li><li>AI 推荐也受租户授权约束，不会跨租户推荐</li><li>本地执行需求通常是接 CLI / Agent，不是直接暴露内网执行路径</li></ul></article></section><section class="brand-card"><p class="brand-kicker">FAQ</p><h2>热更新最常被问到的几个问题</h2><div class="brand-grid brand-grid--two"><article class="brand-card brand-card--nested"><h3>热更新会不会影响其他客户</h3><p>不会。脚本更新完成后，仍然只在所属租户范围内注册和授权，其他租户不会自动获得可见或可执行权限。</p></article><article class="brand-card brand-card--nested"><h3>客户能不能自己上传脚本后直接上线</h3><p>当前 <code>1.0</code> 默认不这样做。平台仍保留审核、注册、授权和权限验证流程，不支持绕过平台直接正式上线。</p></article><article class="brand-card brand-card--nested"><h3>AI 会不会推荐到别的客户能力</h3><p>不会。当前推荐范围受租户和权限共同约束，AI 不会跨租户推荐其他客户的脚本或能力。</p></article><article class="brand-card brand-card--nested"><h3>本地脚本和内网资源能不能接入平台</h3><p>可以，但通常不是让浏览器直接碰本地路径，而是通过 <code>execgov-cli</code> 和后续 Agent 路线承接本地执行桥接。</p></article></div></section><section class="brand-card brand-card--cta"><div class="brand-card__row"><div><p class="brand-kicker">Next Read</p><h2>继续核对交付、文件链路和接入准备</h2><p class="brand-lead">正式交付评估时，把客户流程、文件链路和接入准备清单一起看，会比单独讨论热更新更完整。</p></div><div class="brand-link-grid brand-link-grid--compact"><a class="brand-link-card" href="./customer-flow.html"><span>Delivery</span><strong>客户流程 / 交付</strong></a><a class="brand-link-card" href="./file-results.html"><span>Files</span><strong>文件上传 / 结果下载</strong></a><a class="brand-link-card" href="./onboarding-checklist.html"><span>Checklist</span><strong>客户接入准备清单</strong></a><a class="brand-link-card" href="../contact.html#lead-form"><span>Lead</span><strong>沟通交付 / 分流</strong></a></div></div></section></div>',1)]))}const b=s(r,[["render",d]]);export{h as __pageData,b as default};
